"""Convert HF weights.pt to pusht/lewm_object.ckpt (upstream jepa.JEPA layout)."""from __future__ import annotationsimport jsonimport osimport reimport sysfrom pathlib import Pathdef _strip_target(d: dict) -> dict:    return {k: v for k, v in d.items() if not str(k).startswith("_")}def remap_hf_vit_state_dict_key(key: str) -> str:    """Map legacy HuggingFace ViT keys to stable-pretraining vit_hf layout."""    if not key.startswith("encoder."):        return key    k = key.replace("encoder.encoder.layer.", "encoder.layers.")    k = re.sub(r"\.attention\.attention\.query\.", ".attention.q_proj.", k)    k = re.sub(r"\.attention\.attention\.key\.", ".attention.k_proj.", k)    k = re.sub(r"\.attention\.attention\.value\.", ".attention.v_proj.", k)    k = re.sub(r"\.attention\.output\.dense\.", ".attention.o_proj.", k)    k = re.sub(r"\.intermediate\.dense\.", ".mlp.fc1.", k)    k = re.sub(r"\.output\.dense\.", ".mlp.fc2.", k)    return kdef remap_state_dict(state_dict: dict) -> dict:    return {remap_hf_vit_state_dict_key(k): v for k, v in state_dict.items()}def main() -> int:    upstream = Path(os.environ.get("LEWM_UPSTREAM_ROOT", r"D:\Dev\repos\external\le-wm")).resolve()    stablewm = Path(        os.environ.get("LEWM_STABLEWM_HOME", os.environ.get("STABLEWM_HOME", upstream / ".stable-wm"))    ).resolve()    src = stablewm / "hf_pusht"    out = stablewm / "pusht" / "lewm_object.ckpt"    weights = src / "weights.pt"    config_path = src / "config.json"    if not weights.is_file() or not config_path.is_file():        print("Missing weights.pt or config.json - run download_pusht_assets.ps1", file=sys.stderr)        return 1    sys.path.insert(0, str(upstream))    os.environ["STABLEWM_HOME"] = str(stablewm)    os.chdir(upstream)    import stable_pretraining as spt    import torch    from jepa import JEPA    from module import MLP, ARPredictor, Embedder    cfg = json.loads(config_path.read_text(encoding="utf-8"))    enc = cfg["encoder"]    encoder = spt.backbone.utils.vit_hf(        enc["size"],        patch_size=enc["patch_size"],        image_size=enc["image_size"],        pretrained=enc.get("pretrained", False),        use_mask_token=enc.get("use_mask_token", False),    )    def mlp_block(name: str) -> MLP:        block = _strip_target(cfg[name])        block["norm_fn"] = torch.nn.BatchNorm1d        return MLP(**block)    model = JEPA(        encoder=encoder,        predictor=ARPredictor(**_strip_target(cfg["predictor"])),        action_encoder=Embedder(**_strip_target(cfg["action_encoder"])),        projector=mlp_block("projector"),        pred_proj=mlp_block("pred_proj"),    )    raw = torch.load(weights, map_location="cpu", weights_only=False)    if isinstance(raw, dict) and "state_dict" in raw:        raw = raw["state_dict"]    sd = remap_state_dict(raw)    missing, unexpected = model.load_state_dict(sd, strict=False)    if missing or unexpected:        print(f"load_state_dict mismatch: missing={len(missing)} unexpected={len(unexpected)}", file=sys.stderr)        for k in missing[:8]:            print(f"  missing: {k}", file=sys.stderr)        for k in unexpected[:8]:            print(f"  unexpected: {k}", file=sys.stderr)        return 1    model.eval()    out.parent.mkdir(parents=True, exist_ok=True)    torch.save(model, out)    print(f"Wrote {out} ({out.stat().st_size} bytes)")    return 0if __name__ == "__main__":    raise SystemExit(main())